import { createGlobalStyle } from "styled-components";
export default createGlobalStyle(({ theme }) => `
    *,
    *:before,
    *:after {
        box-sizing: border-box;
        padding: 0;
        margin: 0;
    }

    html {
        color: ${theme.src.color.dark};
        font-family: ${theme.src.fontFamily.primary};
        -webkit-tap-highlight-color: rgba(0, 0, 0, 0);
        -webkit-text-size-adjust: none;
    }

    html,
    body,
    #app {
        height: 100%;
    }

    #app {
        display: flex;
        flex-direction: column;
    }

    ul {
        list-style: none;
        padding: 0;
        margin: 0;
    }

    h1,
    h2,
    h3,
    h4,
    h5,
    h6 {
        margin-bottom: 1rem;
        color: ${theme.src.color.hFont};
        line-height: 100%;
        font-weight: 500;
    }

    h1 {
        font-size: 1.5rem;
    }

    h2 {
        font-size: 1.2rem;
    }

    h3 {
        font-size: 1.1rem;
    }

    h4 {
        font-size: 1rem;
    }

    input {
        -webkit-appearance: none;
    }

    p {
        margin-bottom: .8rem;
        color: ${theme.src.color.pFont};
    }

    a {
        text-decoration: none;

        &:not([href]) {
            cursor: default;
        }
    }

    b {
        font-weight: ${theme.src.fontWeight.semiBold};
    }

    .alert-container {
        h1, h2, h3, h4, h5, h6, p {
            color: inherit !important;
        }
    }

    .CodeMirror {
        padding: 10px;
        border-radius: ${theme.src.radius.card};

        &.cm-s-mdn-liked {
            background: ${theme.src.color.bg};
        }
    }
`);
