import React from "react";
import styled from "styled-components";
import Div from "smart-react-components/element/Div";
const Hamburger = styled(Div).attrs({
    children: React.createElement(React.Fragment, null,
        React.createElement("div", null),
        React.createElement("div", null),
        React.createElement("div", null)),
    display: "flex",
    displayMd: "none"
})(({ theme }) => `
    flex-direction: column;
    justify-content: center;
    align-items: center;
    width: 20px;
    height: 20px;
    margin-right: ${theme.src.length.init};

    div {
        flex: 0 0 auto;
        width: 16px;
        height: 2px;
        margin: 2px 0;
        border-radius: .25rem;
        background: ${theme.src.color.white};
        transition: all 300ms 0s ease-in-out;

        &:nth-child(1) {
            position: relative;
            left: 0;
            top: 0;
        }

        &:nth-child(odd) {
            transform-origin: 0 0;
        }
    }

    &.active > div {
        :nth-child(1) {
            transform: rotate(45deg);
            left: 1px;
            top: 1px;
        }

        :nth-child(2) {
            opacity: 0;
        }

        :nth-child(3) {
            transform: rotate(-45deg);
        }
    }
`);
const HeaderHamburger = ({ active, setActive }) => React.createElement(Hamburger, { className: `${active ? "active" : ""}`, onClick: () => setActive(!active) });
export default HeaderHamburger;
